import { Modal } from 'react-bootstrap';
import React from 'react';
import { navigate } from 'gatsby'; //import navigate from gatsby

function GalleryModal(props) {
  const { image } = props;

  const goHome = index => navigate('/');
  return (
    <Modal
      {...props}
      size="md"
      aria-labelledby="contained-modal-title-vcenter"
      centered
    >
      <Modal.Header closeButton style={{ borderBottom: '0px' }}>
        <Modal.Title id="contained-modal-title-vcenter">
          {image.description}
        </Modal.Title>
      </Modal.Header>
      <Modal.Body style={{ paddingBottom: '0px' }}>
        <div key={image.number}>
          <img
            className="img-fluid gallery-modal-img"
            src={image.link}
            alt={['mage.tags']}
            onClick={() => goHome()}
          />
        </div>
      </Modal.Body>
      <Modal.Footer style={{ borderTop: 'none' }} className="float-left">
        <p className="modal-tags">Aca tenemos una descripcion</p>
        <br />
        <a href="https://cardanobits.art">Link</a>
      </Modal.Footer>
    </Modal>
  );
}

export default GalleryModal;
